class Test:

  def __init__(self):
    self.offentlig = 1  
    self.__privat = "två"   

  def visa_offentlig(self):
    print(self.offentlig)

  def visa_privat(self):
    print(self.__privat)

objekt = Test()
objekt.visa_offentlig()
objekt.visa_privat()

print(objekt.offentlig)
print(objekt.__privat)
